message.content:
@startuml
!theme plain

package "businessRules" as businessRules {
  package "Entity" as entity {
    class User {
      [C]
      email: string
      roles: array
      password: string
      firstname: string
      lastname: string
    }

    class Post {
      [C]
      title: string
      description: string
      createdAt: DateTimeInterface
    }

    class Picture {
      [C]
      name: string
      url: string
    }

    User "One" -- "Many" Post : To
    Post "One" -- "Many" Picture : To
  }
}

@enduml
